#include <stdio.h>
#include <stdlib.h>

int main() {
    FILE *file;
    char buffer[256];

    // Writing to file
    file = fopen("example.txt", "w");
    if (file == NULL) {
        fprintf(stderr, "Error: Could not open file for writing\n");
        return 1;
    }

    fprintf(file, "Hello, file!\n");
    fprintf(file, "This is line 2\n");
    fclose(file);

    // Reading from file
    file = fopen("example.txt", "r");
    if (file == NULL) {
        fprintf(stderr, "Error: Could not open file for reading\n");
        return 1;
    }

    printf("File contents:\n");
    while (fgets(buffer, sizeof(buffer), file) != NULL) {
        printf("%s", buffer);
    }

    fclose(file);
    return 0;
}

#include <stdio.h>
#include <stdlib.h>

int main() {
    int *arr;
    int size = 5;

    // Allocate memory
    arr = (int*)malloc(size * sizeof(int));
    if (arr == NULL) {
        fprintf(stderr, "Memory allocation failed\n");
        return 1;
    }

    // Initialize array
    for (int i = 0; i < size; i++) {
        arr[i] = i * 2;
    }

    // Print array
    printf("Array contents: ");
    for (int i = 0; i < size; i++) {
        printf("%d ", arr[i]);
    }
    printf("\n");

    // Reallocate to larger size
    size = 10;
    arr = (int*)realloc(arr, size * sizeof(int));
    if (arr == NULL) {
        fprintf(stderr, "Memory reallocation failed\n");
        return 1;
    }

    // Initialize new elements
    for (int i = 5; i < size; i++) {
        arr[i] = i * 3;
    }

    // Print expanded array
    printf("Expanded array: ");
    for (int i = 0; i < size; i++) {
        printf("%d ", arr[i]);
    }
    printf("\n");

    // Free memory
    free(arr);
    return 0;
}

#include <stdio.h>
#include <string.h>
#include <stdlib.h>

// Structure definition
typedef struct {
    char name[50];
    int age;
    float salary;
} Employee;

// Function to create and initialize employee
Employee* create_employee(const char* name, int age, float salary) {
    Employee* emp = (Employee*)malloc(sizeof(Employee));
    if (emp == NULL) {
        return NULL;
    }

    strncpy(emp->name, name, sizeof(emp->name) - 1);
    emp->name[sizeof(emp->name) - 1] = '\0';
    emp->age = age;
    emp->salary = salary;

    return emp;
}

// Function to print employee information
void print_employee(const Employee* emp) {
    if (emp != NULL) {
        printf("Employee: %s, Age: %d, Salary: $%.2f\n", 
               emp->name, emp->age, emp->salary);
    }
}

int main() {
    Employee emp1;
    Employee* emp2;

    // Static initialization
    strcpy(emp1.name, "John Doe");
    emp1.age = 30;
    emp1.salary = 50000.0;

    // Dynamic initialization
    emp2 = create_employee("Jane Smith", 28, 55000.0);

    printf("Employee Information:\n");
    print_employee(&emp1);
    print_employee(emp2);

    // Clean up
    free(emp2);
    return 0;
}

#include <stdio.h>
#include <stdlib.h>

// Node structure
typedef struct Node {
    int data;
    struct Node* next;
} Node;

// Function to create a new node
Node* create_node(int data) {
    Node* new_node = (Node*)malloc(sizeof(Node));
    if (new_node == NULL) {
        fprintf(stderr, "Memory allocation failed\n");
        exit(1);
    }
    new_node->data = data;
    new_node->next = NULL;
    return new_node;
}

// Function to insert at beginning
Node* insert_front(Node* head, int data) {
    Node* new_node = create_node(data);
    new_node->next = head;
    return new_node;
}

// Function to print the list
void print_list(Node* head) {
    Node* current = head;
    printf("List: ");
    while (current != NULL) {
        printf("%d -> ", current->data);
        current = current->next;
    }
    printf("NULL\n");
}

// Function to free the list
void free_list(Node* head) {
    Node* current = head;
    while (current != NULL) {
        Node* temp = current;
        current = current->next;
        free(temp);
    }
}

int main() {
    Node* head = NULL;

    // Insert some elements
    head = insert_front(head, 10);
    head = insert_front(head, 20);
    head = insert_front(head, 30);

    print_list(head);

    // Clean up
    free_list(head);
    return 0;
}

#include <stdio.h>
#include <string.h>
#include <stdlib.h>
#include <ctype.h>

// Function to convert string to uppercase
void to_uppercase(char* str) {
    for (int i = 0; str[i]; i++) {
        str[i] = toupper(str[i]);
    }
}

// Function to reverse a string
void reverse_string(char* str) {
    int len = strlen(str);
    for (int i = 0; i < len / 2; i++) {
        char temp = str[i];
        str[i] = str[len - 1 - i];
        str[len - 1 - i] = temp;
    }
}

// Function to count words in a string
int count_words(const char* str) {
    int count = 0;
    int in_word = 0;

    for (int i = 0; str[i]; i++) {
        if (isspace(str[i])) {
            in_word = 0;
        } else if (!in_word) {
            in_word = 1;
            count++;
        }
    }

    return count;
}

int main() {
    char text[] = "Hello, World! This is a test string.";
    char copy[100];

    printf("Original string: %s\n", text);
    printf("Length: %zu\n", strlen(text));
    printf("Word count: %d\n", count_words(text));

    // Make a copy for manipulation
    strcpy(copy, text);
    to_uppercase(copy);
    printf("Uppercase: %s\n", copy);

    // Reverse the copy
    reverse_string(copy);
    printf("Reversed: %s\n", copy);

    return 0;
}

#include <stdio.h>

// Sample functions
int add(int a, int b) {
    return a + b;
}

int multiply(int a, int b) {
    return a * b;
}

int subtract(int a, int b) {
    return a - b;
}

// Function that takes a function pointer as parameter
int calculate(int x, int y, int (*operation)(int, int)) {
    return operation(x, y);
}

// Array of function pointers
typedef int (*MathOperation)(int, int);

int main() {
    // Direct function pointer usage
    int (*func_ptr)(int, int) = add;
    printf("Using function pointer directly: %d\n", func_ptr(5, 3));

    // Using function pointer as parameter
    printf("Addition: %d\n", calculate(10, 5, add));
    printf("Multiplication: %d\n", calculate(10, 5, multiply));
    printf("Subtraction: %d\n", calculate(10, 5, subtract));

    // Array of function pointers
    MathOperation operations[] = {add, subtract, multiply};
    const char* op_names[] = {"Add", "Subtract", "Multiply"};

    int a = 12, b = 4;
    printf("\nOperations on %d and %d:\n", a, b);
    for (int i = 0; i < 3; i++) {
        printf("%s: %d\n", op_names[i], operations[i](a, b));
    }

    return 0;
}
